example.code:
let s1 = String::from("hello");
let s3 = s1;        // s1 moved to s3; s1 no longer valid
// println!("{s1}"); // compile error: value borrowed after move

let x: i32 = 5;
let y = x;          // i32 is Copy; both x and y are valid
println!("{x} {y}");

let mut s = String::from("hello");

// Multiple shared borrows OK
let r1 = &s;
let r2 = &s;
println!("{r1} {r2}");   // last use of r1, r2

// After last use of shared borrows, exclusive borrow is legal
let r3 = &mut s;
r3.push_str("!");

// Explicit lifetime needed: compiler can't know which input the output borrows from
fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

use std::sync::Arc;

let counter = Arc::new(Mutex::new(0u64));
let counter2 = Arc::clone(&counter);  // O(1) clone — increments refcount

tokio::spawn(async move {
    *counter2.lock().unwrap() += 1;
});

use std::borrow::Cow;

fn sanitize(input: &str) -> Cow<str> {
    if input.contains("badword") {
        Cow::Owned(input.replace("badword", "***"))
    } else {
        Cow::Borrowed(input)  // no allocation when clean
    }
}

struct RequestBuilder {
    url: String,
    method: String,
    headers: Vec<(String, String)>,
}

impl RequestBuilder {
    pub fn new(url: impl Into<String>) -> Self {
        Self { url: url.into(), method: "GET".into(), headers: vec![] }
    }

    pub fn method(mut self, method: impl Into<String>) -> Self {
        self.method = method.into();
        self
    }

    pub fn header(mut self, k: impl Into<String>, v: impl Into<String>) -> Self {
        self.headers.push((k.into(), v.into()));
        self
    }

    pub fn build(self) -> Request {
        Request { url: self.url, method: self.method, headers: self.headers }
    }
}

struct User { name: String, email: String }

impl User {
    pub fn name(&self) -> &str { &self.name }          // borrows
    pub fn set_name(&mut self, name: String) { self.name = name; }  // mutably borrows
    pub fn into_name(self) -> String { self.name }     // consumes
}

let user_id = 42u64;
tokio::spawn(async move {
    fetch_user(user_id).await   // user_id moved into closure; no borrow issue
});

// BAD: agents make `shared_ref` 'static by leaking
// GOOD: Arc::clone passes ownership
let db = Arc::clone(&state.db);
tokio::spawn(async move {
    db.fetch_user(42).await
});
